import React, { useState } from "react";
import axios from "axios";

import districtOptions from "../data/district_options.json";
import commodityOptions from "../data/commodity_options.json";

const CropPriceLookup = () => {
    const [district, setDistrict] = useState("");
    const [commodity, setCommodity] = useState("");
    const [prices, setPrices] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchPrices = async () => {
        if (!commodity || !district) {
            setError("Please select both commodity and district.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.post("http://localhost:5000/api/crops/getPrices", {
                Commodity: commodity,
                District: district,
            });
            setPrices(response.data);
        } catch (err) {
            setError("Failed to fetch price data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-lg mx-auto p-8 bg-gradient-to-r from-green-400 via-blue-500 to-purple-600 shadow-2xl rounded-lg border border-gray-300 text-black">
            <h2 className="text-4xl font-bold text-center mb-8 drop-shadow-lg">🌾 Crop Price Lookup 🌾</h2>
            
            <div className="flex flex-col items-center space-y-6">
                <div className="w-full max-w-md">
                    <label className="block text-white text-lg font-semibold mb-2 text-center">Select Commodity</label>
                    <select 
                        value={commodity} 
                        onChange={(e) => setCommodity(e.target.value)} 
                        className="w-full p-4 border-4 border-white rounded-xl bg-white/90 text-gray-900 shadow-lg focus:ring-2 focus:ring-yellow-400 text-center text-lg transition-all duration-300 hover:border-yellow-300"
                    >
                        <option value="">Choose your crop</option>
                        {commodityOptions.map((item, index) => (
                            <option key={index} value={item}>{item}</option>
                        ))}
                    </select>
                </div>

                <div className="w-full max-w-md">
                    <label className="block text-white text-lg font-semibold mb-2 text-center">Select District</label>
                    <select 
                        value={district} 
                        onChange={(e) => setDistrict(e.target.value)} 
                        className="w-full p-4 border-4 border-white rounded-xl bg-white/90 text-gray-900 shadow-lg focus:ring-2 focus:ring-yellow-400 text-center text-lg transition-all duration-300 hover:border-yellow-300"
                    >
                        <option value="">Choose your district</option>
                        {districtOptions.map((item, index) => (
                            <option key={index} value={item}>{item}</option>
                        ))}
                    </select>
                </div>
            </div>
            
            <div className="flex justify-center mt-8">
                <button 
                    onClick={fetchPrices} 
                    className="px-8 py-4 bg-yellow-400 text-gray-900 font-bold rounded-xl shadow-xl hover:bg-yellow-500 transition-all duration-300 transform hover:scale-105 border-2 border-white"
                >
                    🔍 Get Prices
                </button>
            </div>
            
            {loading && (
                <div className="mt-6 text-center">
                    <p className="text-white animate-pulse text-lg">Loading prices...</p>
                </div>
            )}
            
            {error && (
                <div className="mt-6 p-4 bg-red-100 border-2 border-red-300 rounded-xl">
                    <p className="text-red-700 font-semibold text-center">{error}</p>
                </div>
            )}
            
            {prices && (
                <div className="mt-8 p-6 bg-white/90 text-gray-900 rounded-xl shadow-2xl border-2 border-white">
                    <h3 className="text-2xl font-semibold text-gray-700 text-center mb-6">📊 Price Details 📊</h3>
                    <div className="space-y-4">
                        {prices.map((data, index) => (
                            <div key={index} className="p-4 bg-gradient-to-r from-yellow-300 to-orange-400 shadow-md rounded-xl border-2 border-white">
                                <p className="font-semibold text-center text-lg mb-2"><strong>Grade:</strong> {data.Grade}</p>
                                <div className="grid grid-cols-2 gap-2 text-center">
                                    <p><strong>Min Price:</strong> {data["Min Price"]} ₹</p>
                                    <p><strong>Max Price:</strong> {data["Max Price"]} ₹</p>
                                    <p className="col-span-2"><strong>Modal Price:</strong> {data["Modal Price"]} ₹</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

export default CropPriceLookup;
